module.exports = {
  solidity: "0.8.28",
  networks: {
    polkadotTestnet: {
      url: "https://testnet-passet-hub-eth-rpc.polkadot.io",
      chainId: 420420417,
      accounts: process.env.PRIVATE_KEY ? [process.env.PRIVATE_KEY] : [],
    },
  },
  etherscan: {
    apiKey: {
