"use client";

import { useState } from "react";
import Link from "next/link";
import { useMarkets } from "@/hooks/useMarkets";
import { MarketCard } from "@/components/MarketCard";
import { SkeletonCard } from "@/components/SkeletonCard";
import { MarketStatus } from "@/lib/contract";

const FILTERS = [
  { label: "All", value: -1 },
  { label: "Open", value: MarketStatus.OPEN },
  { label: "Proposed", value: MarketStatus.PROPOSED },
  { label: "Resolved", value: MarketStatus.RESOLVED },
  { label: "Cancelled", value: MarketStatus.CANCELLED },
] as const;

export default function HomePage() {
  const { markets, marketCount, isLoading } = useMarkets();
  const [filter, setFilter] = useState(-1);

  const filteredMarkets = markets
    ? [...markets]
        .map((m, i) => ({ market: m, id: i }))
        .filter((m) => filter === -1 || m.market.status === filter)
        .reverse()
    : [];

  return (
    <div>
      {/* Hero */}
      <div className="text-center mb-10">
        <h1 className="text-4xl font-bold mb-2">
          <span className="text-white">Poly</span>
          <span className="text-[#e6007a]">Dot</span>
        </h1>
        <p className="text-slate-400 mb-6 max-w-lg mx-auto">
          Decentralized prediction markets on Polkadot Hub. Bet PAS on YES/NO outcomes.
        </p>
        <div className="flex gap-3 justify-center">
          <Link
            href="/create"
            className="bg-[#e6007a] text-white font-bold rounded-xl px-5 py-2.5 hover:bg-[#e6007a]/90 transition-colors text-sm"
          >
            Create Market
          </Link>
