"use client";

import { useReadContract } from "wagmi";
import { CONTRACT_ADDRESS, POLYDOT_ABI } from "@/lib/contract";

export function useMarkets() {
  const { data: markets, isLoading, error } = useReadContract({
    address: CONTRACT_ADDRESS,
    abi: POLYDOT_ABI,
    functionName: "getAllMarkets",
    query: { refetchInterval: 30000 },
  });

  const { data: count } = useReadContract({
    address: CONTRACT_ADDRESS,
    abi: POLYDOT_ABI,
    functionName: "marketCount",
    query: { refetchInterval: 30000 },
  });

  return {
    markets: markets as readonly {
      question: string;
      creator: string;
      deadline: bigint;
      yesPool: bigint;
      noPool: bigint;
      createdAt: bigint;
      status: number;
      result: number;
    }[] | undefined,
    marketCount: count ? Number(count) : 0,
    isLoading,
    error,
  };
}

"use client";

export function OddsBar({ yesPct, noPct }: { yesPct: number; noPct: number }) {
  return (
    <div>
      <div className="flex justify-between mb-1">
        <span className="text-xs font-bold text-green-400">YES {yesPct}%</span>
        <span className="text-xs font-bold text-red-400">NO {noPct}%</span>
      </div>
      <div className="h-2 rounded-full bg-[#1c1c28] overflow-hidden flex">
        <div
          className="h-full bg-green-500 transition-all duration-500"
          style={{ width: `${yesPct}%` }}
        />
        <div
          className="h-full bg-red-500 transition-all duration-500"
          style={{ width: `${noPct}%` }}
        />
      </div>
    </div>
  );
}

"use client";

export function SkeletonCard() {
  return (
    <div className="rounded-2xl bg-[#111118] border border-[#1c1c28] p-5 animate-pulse">
      <div className="flex justify-between mb-3">
        <div className="h-5 bg-[#1c1c28] rounded w-16" />
        <div className="h-5 bg-[#1c1c28] rounded w-12" />
      </div>
      <div className="h-4 bg-[#1c1c28] rounded w-full mb-2" />
      <div className="h-4 bg-[#1c1c28] rounded w-3/4 mb-4" />
      <div className="h-2 bg-[#1c1c28] rounded-full w-full mb-3" />
      <div className="flex justify-between">
        <div className="h-3 bg-[#1c1c28] rounded w-20" />
        <div className="h-3 bg-[#1c1c28] rounded w-20" />
      </div>
    </div>
  );
}

